package com.google.gson.internal.bind;
import com.google.gson.JsonSyntaxException;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.internal.JavaVersion;
import com.google.gson.internal.PreJava9DateFormatProvider;
import com.google.gson.internal.bind.util.ISO8601Utils;
import com.google.gson.stream.JsonWriter;
import java.text.DateFormat;
import java.text.ParseException;
import java.text.ParsePosition;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.lang.reflect.Method;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateType;

    @BeforeEach
    void setUp() throws Exception {
        dateType = mock(DefaultDateTypeAdapter.DateType.class);

        // Use reflection to get constructor with (DateType<T>, int) since String constructor doesn't exist
        var constructor = DefaultDateTypeAdapter.class.getDeclaredConstructor(DefaultDateTypeAdapter.DateType.class, int.class);
        constructor.setAccessible(true);
        adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateType, 0);
    }

    @Test
    void read_shouldReturnNull_whenJsonTokenIsNull() throws IOException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.NULL);

        Date result = adapter.read(in);

        InOrder inOrder = inOrder(in);
        inOrder.verify(in).peek();
        inOrder.verify(in).nextNull();
        assertNull(result);
    }

    @Test
    void read_shouldReturnDeserializedDate_whenJsonTokenIsNotNull() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);

        Date expectedDate = new Date();
        when(dateType.deserialize(any(Date.class))).thenReturn(expectedDate);

        // Use reflection to invoke private deserializeToDate method
        Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Spy adapter to mock deserializeToDate via reflection
        DefaultDateTypeAdapter<Date> spyAdapter = spy(adapter);

        doAnswer(invocation -> expectedDate).when(spyAdapter).read(any(JsonReader.class)); // fallback

        // Instead of mocking private method, mock read method partially:
        // But since we want to test read(), we must mock deserializeToDate via reflection

        // Use reflection to call read() but intercept deserializeToDate call by mocking adapter
        // Since deserializeToDate is private, we cannot mock it directly with Mockito.
        // Instead, we can create a subclass that overrides read() for testing or use reflection to call deserializeToDate directly.

        // Here we will call read() and intercept deserializeToDate via reflection to return expectedDate:
        // So we create a proxy method to replace deserializeToDate via reflection:

        // Create a spy that calls real read(), but we override deserializeToDate via reflection:
        // For this test, directly call deserializeToDateMethod.invoke(spyAdapter, in) to simulate.

        // Because mocking private method is not possible, we call read() on a spy and verify calls:

        // Instead, call deserializeToDateMethod.invoke(spyAdapter, in) to get expectedDate and then call read()

        // Setup spy to call real read()
        doCallRealMethod().when(spyAdapter).read(in);

        // Mock deserializeToDate method to return expectedDate via reflection hack:
        // We cannot mock private method with Mockito, so we use a wrapper:

        // Use reflection to replace private method temporarily is complex,
        // So we just test read() by calling deserializeToDate directly and then calling dateType.deserialize

        // Call deserializeToDate directly
        Date deserializedDate = (Date) deserializeToDateMethod.invoke(adapter, in);
        // Mock dateType.deserialize to return expectedDate when passed deserializedDate
        when(dateType.deserialize(deserializedDate)).thenReturn(expectedDate);

        // Now call read()
        Date result = adapter.read(in);

        InOrder inOrder = inOrder(in, dateType);
        inOrder.verify(in).peek();
        inOrder.verify(in).nextString(); // read() calls in.nextString() inside deserializeToDate
        inOrder.verify(dateType).deserialize(deserializedDate);

        assertEquals(expectedDate, result);
    }
}
